SELECT COUNT(*) AS total_cybersecurity_events
FROM events
WHERE category_id = (SELECT category_id FROM event_categories WHERE category_name = 'Cybersecurity');

SELECT AVG((strftime('%s', e.end_time) - strftime('%s', e.start_time)) / 60.0) AS average_duration_minutes
FROM events e
JOIN attendances a ON e.event_id = a.event_id;

SELECT COUNT(*) AS feedback_count
FROM event_attendee_feedback
WHERE event_id = 0;

SELECT COUNT(DISTINCT attendee_id) AS number_of_feedbacks
FROM event_attendee_feedback
WHERE event_id = 0;

SELECT MAX(rating) AS highest_rating
FROM event_attendee_feedback
WHERE event_id = 0;
